 963 /// Replace function F by function G.
 964 void MergeFunctions::replaceFunctionInTree(const FunctionNode &FN,
 965                                            Function *G) {
 966   Function *F = FN.getFunc();
 967   assert(FunctionComparator(F, G, &GlobalNumbers).compare() == 0 &&
 968          "The two functions must be equal");
 969 
 970   auto I = FNodesInTree.find(F);
 971   assert(I != FNodesInTree.end() && "F should be in FNodesInTree");
 972   assert(FNodesInTree.count(G) == 0 && "FNodesInTree should not contain G");
 973 
 974   FnTreeType::iterator IterToFNInFnTree = I->second;
 975   assert(&(*IterToFNInFnTree) == &FN && "F should map to FN in FNodesInTree.");
 976   // Remove F -> FN and insert G -> FN
 977   FNodesInTree.erase(I);
 978   FNodesInTree.insert({G, IterToFNInFnTree});
 979   // Replace F with G in FN, which is stored inside the FnTree.
 980   FN.replaceBy(G);
 981 }
